#include<bits/stdc++.h>
using namespace std;
int dp[1005][105];
int c[105],v[105];
int main() {
    int t,m;
    cin>>t>>m;
    for(int i=1;i<=m;i++){
        cin>>v[i]>>c[i];
    }
    for(int i=1;i<=m;i++){
        for(int j=1;j<=t;j++){
            if(j>=v[i]){
                dp[i][j]=max(dp[i-1][j],dp[i-1][j-v[i]]+c[i]);
            }else{
                dp[i][j]=dp[i-1][j];
            }
        }
    }
    cout<<dp[m][t];
    return 0;
}
